sparql_query:
PREFIX goo:    <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:   <http://example.org/resource#>
PREFIX xsd:    <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:    <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:   <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?adminDivision ?sviRecord2000 ?svi2000 ?povertyRate2000 ?sviRecord2010 ?svi2010 ?povertyRate2010 ?sviRecord2020 ?svi2020 ?povertyRate2020 ?populationIncrease2000To2020
WHERE {
  ?adminDivision a goo:County .
  ?sviRecord2000 a goo:SVIRecord ;
                 goo:representsCounty ?adminDivision ;
                 goo:sviYear 2000 ;
                 goo:sviOverallScore ?svi2000 ;
                 goo:povertyRate ?povertyRate2000 ;
                 goo:totalPopulation ?population2000 .
  ?sviRecord2010 a goo:SVIRecord ;
                 goo:representsCounty ?adminDivision ;
                 goo:sviYear 2010 ;
                 goo:sviOverallScore ?svi2010 ;
                 goo:povertyRate ?povertyRate2010 .
  ?sviRecord2020 a goo:SVIRecord ;
                 goo:representsCounty ?adminDivision ;
                 goo:sviYear 2020 ;
                 goo:sviOverallScore ?svi2020 ;
                 goo:povertyRate ?povertyRate2020 ;
                 goo:totalPopulation ?population2020 .
  BIND((xsd:integer(?population2020) - xsd:integer(?population2000)) AS ?populationIncrease2000To2020)
}
ORDER BY DESC(?svi2020) ?adminDivision
LIMIT 10
